for label, pat in queries:
    hits=[]
    rx=re.compile(pat, re.I)
    with path.open() as f:
        for i,line in enumerate(f,1):
            if rx.search(line):
                try:
                    a=json.loads(line)
                    hits.append((i,a.get('date_publish'),a.get('source'),a.get('title')))
                except Exception:
                    hits.append((i,None,None,line[:120]))
                if len(hits)>=8: break
    print('\\n--', label, len(hits),'--')
    for h in hits: print(h)
